let Baseline = SigninLogs | where TimeGenerated between (ago(30d) .. ago(1d)) | summarize AvgDaily = count()/30.0 by UserPrincipalName;
let Today = SigninLogs | where TimeGenerated > ago(1d) | summarize TodayCount=count() by UserPrincipalName;
Today | join kind=leftouter Baseline on UserPrincipalName | extend Ratio=todouble(TodayCount)/iff(AvgDaily>0,AvgDaily,1.0) | where Ratio > 5

let History = SigninLogs | where TimeGenerated between (ago(30d) .. ago(1d)) | summarize PastCountries=make_set(tostring(LocationDetails.countryOrRegion)) by UserPrincipalName;
let Today = SigninLogs | where TimeGenerated > ago(1d) | summarize TodayCountries=make_set(tostring(LocationDetails.countryOrRegion)) by UserPrincipalName;
Today | join kind=leftouter History on UserPrincipalName | extend NewCountries=set_difference(TodayCountries, PastCountries) | where array_length(NewCountries) > 0

let A = datatable(Account:string, ScoreA:int) ["alice", 3, "bob", 0];
let B = datatable(Account:string, ScoreB:int) ["alice", 2, "charlie", 5];
A | join kind=fullouter B on Account | extend Total = coalesce(ScoreA, 0) + coalesce(ScoreB, 0)

let FailScore = SecurityEvent | where TimeGenerated > ago(1d) | where EventID == 4625 | summarize F=count() by Account | extend FScore=iff(F>10, 2, iff(F>5, 1, 0));
let NightScore = SigninLogs | where TimeGenerated > ago(1d) | where hourofday(TimeGenerated) !between (8 .. 18) | summarize N=count() by Account=UserPrincipalName | extend NScore=1;
FailScore | join kind=fullouter NightScore on Account | extend Total=coalesce(FScore,0)+coalesce(NScore,0) | where Total > 1 | sort by Total desc
